// 落到 shadow 容器内(widget 零足迹)。ECharts 全渲染在容器内(canvas + tooltip 子 div),不注入 document.head → ZF 安全
const el = document.createElement('div'); el.style.height = '400px';
shadowRoot.appendChild(el);
const chart = echarts.init(el);
chart.setOption(option);
new ResizeObserver(() => chart.resize()).observe(el);
